  "question": "In obstructive jaundice all are true except :",
  "options": {
    "A": "serum conjugated bilirubin is increased",
    "B": "serum unconjugated bilirubin is increased",
    "C": "urinary urobilnogen is reduced",
    "D": "urinary congugated bilirubin is increased",
    "E": "fecal stercobilingen is reduced"
  },
